/* ══════════════════════════════════════════════════════════════
   HELPER UTILITIES
══════════════════════════════════════════════════════════════ */
function filterByCategory(cat){if(!cat||cat==='all')return[...properties];return properties.filter(p=>p.category===cat);}
function filterByLocality(loc){const q=loc.toLowerCase();return properties.filter(p=>p.locality.toLowerCase().includes(q));}
function filterByMaxRent(max){return properties.filter(p=>p.category!=='buy'&&p.priceNum<=max);}
function filterByMaxBuyPrice(max){return properties.filter(p=>p.category==='buy'&&p.priceNum<=max);}
function filterByBHK(bhk){return properties.filter(p=>p.bhk===bhk);}
function filterByFurnishing(type){return properties.filter(p=>p.furnished===type);}
function filterByGender(gender){return properties.filter(p=>p.genderPreference===gender);}
function filterByMetroDistance(maxKm){return properties.filter(p=>p.distanceMetro<=maxKm);}
function filterByBusDistance(maxKm){return properties.filter(p=>p.distanceBus<=maxKm);}
function filterByAmenity(amenity){return properties.filter(p=>p.amenities.includes(amenity));}
function getPropertyById(id){return properties.find(p=>p.id===id)||null;}
function getFeatured(){return properties.filter(p=>p.featured);}
function filterListings(opts={}){return properties.filter(p=>{if(opts.category&&opts.category!=='all'&&p.category!==opts.category)return false;if(opts.locality&&!p.locality.toLowerCase().includes(opts.locality.toLowerCase()))return false;if(opts.maxPrice!=null&&p.priceNum>opts.maxPrice)return false;if(opts.bhk!=null&&p.bhk!==opts.bhk)return false;if(opts.furnished&&p.furnished!==opts.furnished)return false;if(opts.gender&&p.genderPreference!==opts.gender)return false;if(opts.maxMetro!=null&&p.distanceMetro>opts.maxMetro)return false;if(opts.maxBus!=null&&p.distanceBus>opts.maxBus)return false;if(opts.amenity&&!p.amenities.includes(opts.amenity))return false;if(opts.propertyType&&p.propertyType!==opts.propertyType)return false;return true;});}